INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$No-download browser-based rooms$q$, $q$Hosts and attendees join webinars directly from a web browser on desktop or mobile, with no software installation required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Live webinars$q$, $q$Standard real-time webinar sessions with host controls for video, slides, and audience interaction.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Automated (evergreen) webinars$q$, $q$A recorded session is scheduled to replay automatically at set times, with timed polls, handouts, and calls to action to keep it feeling interactive.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Series webinars$q$, $q$A single event can be scheduled across multiple sessions for recurring programs like onboarding or multi-part training.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$On-demand webinars$q$, $q$Visitors can watch a recorded session at any time from an on-demand landing page.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Engagement tools$q$, $q$Live polls, downloadable handouts, and scheduled calls to action can be triggered during a session to drive registrant interaction and conversions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Registration pages$q$, $q$Customizable registration and thank-you pages can be built and embedded without a separate landing page tool.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Analytics and reporting$q$, $q$Post-event reporting covers registration, attendance, drop-off, and engagement data for each session.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Integrations and API$q$, $q$Native integrations with marketing automation and CRM tools, plus a documented API and Zapier support, allow registrant and attendance data to sync with an existing marketing stack.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Recording and replay$q$, $q$Live sessions can be recorded and repurposed as on-demand or automated events.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$No-download join experience reduces friction for webinar attendees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Multiple event formats (live, series, automated, on-demand) from one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Strong built-in engagement tools like timed polls, handouts, and calls to action$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Clean, modern interface for both hosts and attendees$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Integrates with common marketing automation and CRM tools via native integrations, Zapier, and an API$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$No permanent free plan, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Costs increase with both the number of hosts and attendee capacity tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Not built for large multi-track virtual conferences or expo-style events$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Lighter on formal learning-management features than dedicated course platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Advanced branding and customization options are more limited on lower-tier plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Do attendees need to download anything to join a Demio webinar?$q$, $q$No. Demio is browser-based, so hosts and attendees join sessions directly through a web browser on desktop or mobile without installing any software.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$What is an automated webinar in Demio?$q$, $q$An automated (or evergreen) webinar replays a previously recorded session on a set schedule while still displaying timed polls, handouts, and calls to action, so it can generate leads on an ongoing basis without a host presenting live each time.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Does Demio offer a free plan?$q$, $q$Demio does not offer a permanent free plan. It offers a free trial period so prospective customers can test the platform before committing to a paid plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$What integrations does Demio support?$q$, $q$Demio integrates natively with a number of marketing automation and CRM platforms and also connects to thousands of other apps through Zapier, in addition to offering its own API for custom workflows around registrations and attendance data.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$How many attendees can a Demio webinar hold?$q$, $q$Attendee capacity depends on the plan and pricing tier selected, ranging from smaller rooms on entry-level plans up to several thousand attendees on higher tiers.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$B2B product demo and lead-generation webinars$q$, $q$Marketing teams run recurring live webinars to introduce a product, capture registrant data, and hand qualified leads to sales.$q$, $q$B2B marketing and demand-generation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Evergreen lead-generation funnels$q$, $q$A single recorded presentation is turned into an automated webinar that runs on a recurring schedule, continuously generating leads without a live host.$q$, $q$Growth marketers and funnel builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Customer onboarding and training series$q$, $q$Series webinars deliver a multi-part onboarding or training program to customers or new users across several scheduled sessions.$q$, $q$Customer success and onboarding teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Agency and consultant client webinars$q$, $q$Agencies host branded webinars on behalf of clients, using registration pages and analytics to report on engagement and results.$q$, $q$Marketing agencies and consultants$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Starter$q$, $q$$45/month per host (billed annually); $99/month if billed monthly$q$, $q$Monthly or annual$q$, $q$["Up to 50 attendees","Live webinars","Registration pages","Basic engagement tools","Analytics dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Growth$q$, $q$From $80/month per host (billed annually), varies by attendee capacity$q$, $q$Monthly or annual$q$, $q$["Attendee capacity from 150 up to 3,000","Automated and series webinars","Advanced engagement tools","Native marketing integrations","Custom registration branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Premium$q$, $q$From $196/month per host (billed annually), varies by attendee capacity$q$, $q$Monthly or annual$q$, $q$["Higher attendee capacity tiers","Priority support","Advanced analytics and reporting","Additional customization options","API access"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Demio is a browser-based webinar and virtual event platform built for marketing teams that use webinars as a demand-generation and customer-education channel. Instead of requiring a desktop app or plugin, both hosts and attendees join a Demio room directly from a web browser, which removes a common source of drop-off in webinar funnels. The platform is positioned less as a general video-conferencing tool and more as a purpose-built environment for scheduled, promoted webinar events.$q$, $q$The product supports several event formats from a single dashboard: live webinars run in real time, series events repeat a session across multiple scheduled sessions, automated (sometimes called evergreen) webinars replay a pre-recorded session on a set schedule while still surfacing timed polls and calls to action, and on-demand webinars let visitors watch a recording whenever they choose. This range lets a marketing team reuse one core presentation across several delivery styles without rebuilding it each time.$q$, $q$Demio also includes registration page creation, attendee engagement features such as polls, handouts, and calls to action, post-event analytics, and integrations with common marketing automation and CRM tools. It was acquired by Banzai International in 2021 and continues to operate as a distinct product under that company, which also owns other event and engagement marketing tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$who-demio-is-for$q$, $q$Who Demio Is For$q$, 2, ARRAY[$q$Demio is best suited to B2B marketing and demand-generation teams that run webinars as a recurring part of their funnel, such as product demos, lead-generation events, or customer onboarding sessions. Its combination of registration pages, engagement prompts, and analytics maps closely to how marketers already think about webinars as a conversion channel rather than just a meeting format.$q$, $q$SaaS companies and agencies that want to turn a single presentation into an ongoing, semi-automated lead source are a strong fit, since the automated and series webinar formats let a recorded session run repeatedly with minimal manual effort while still looking live to attendees. Course creators and coaches running smaller cohorts also use Demio for its simplicity and no-download attendee experience.$q$, $q$Teams that already have a webinar workflow built around simple, single-session live events but want cleaner registration pages, better engagement tools, and more polished analytics than a generic video-call tool provides will find Demio a natural upgrade without a steep learning curve for either hosts or attendees.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations planning large-scale virtual conferences with multiple concurrent tracks, expo-style networking, or thousands of simultaneous attendees on a single event are likely to outgrow what Demio is designed for; it is built around single-room webinar sessions rather than multi-track conference production.$q$, $q$Teams that need deep learning-management functionality, such as structured course sequences, quizzes, certificates, or drip-fed curricula, should look at a dedicated online course or LMS platform instead, since Demio's automated and series formats are aimed at marketing webinars rather than formal education delivery.$q$, $q$Budget-sensitive solo users or very early-stage founders who want a permanently free plan should also be cautious, since Demio does not offer an indefinite free tier; access is limited to a time-boxed free trial before a paid plan is required, and attendee capacity is tiered by plan, which can push costs up quickly as an audience grows.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Demio is its no-download webinar room: attendees click a join link and enter the session directly in their browser on desktop or mobile, while hosts get a control panel for managing slides, video, chat, and audience interaction without separate software. This is paired with registration pages that can be customized and embedded to capture sign-ups ahead of an event.$q$, $q$Engagement features are a major focus, including live polls, downloadable handouts, and timed calls to action that can appear during a session to drive clicks toward a pricing page, booking link, or offer. In automated and series events, these same engagement elements can be scheduled to appear at fixed points in the recording, so a pre-recorded session still behaves interactively for the viewer.$q$, $q$Beyond the room itself, Demio provides post-event analytics covering registration and attendance rates, engagement actions taken during the session, and drop-off points, along with integrations to marketing automation platforms and CRMs so registrant and attendance data can flow into a team's existing stack. A documented API and Zapier integration extend this further for teams that want custom workflows around registrations and follow-up.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$the-demio-experience$q$, $q$The Demio Experience$q$, 2, ARRAY[$q$Setting up an event in Demio typically starts with choosing an event type, building a registration page from a template, and configuring the session itself, including uploaded slides or video and any polls, handouts, or calls to action to trigger during the presentation. The interface is generally described as clean and modern compared to older webinar tools, with most core actions reachable from a single dashboard.$q$, $q$During a live session, the host view separates presentation controls from audience management, so a presenter can advance slides or trigger a call to action while a co-host or moderator handles incoming chat questions. Attendees see a simplified, distraction-light room focused on the presentation, chat, and any active engagement elements, with no login or app install required to participate.$q$, $q$After an event ends, hosts land on a reporting view summarizing attendance, engagement, and registrant activity, which is where the platform's marketing orientation is most visible: the emphasis throughout the experience is on turning webinar attendance into measurable pipeline activity rather than simply hosting a video call.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Employee Scheduling$q$, $q$Build and publish shift rosters with drag-and-drop tools, shift templates, and copy-previous-week options, factoring in staff availability, qualifications, and requested time off.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Time & Attendance$q$, $q$Staff clock in and out via the mobile app, a shared tablet kiosk with photo capture, or a browser, with timesheets that reconcile automatically against the published schedule.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Auto-Scheduling & Demand Forecasting$q$, $q$Available on higher plan tiers, this uses historical sales or foot-traffic data to recommend staffing levels and can auto-generate draft schedules for a manager to review.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Task Management (Tasking)$q$, $q$Assign checklists and to-do items tied to a specific shift or location, such as opening and closing duties, so operational tasks are tracked alongside attendance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Team Communication$q$, $q$A built-in news feed and messaging tool lets managers post shift notes and company-wide announcements, and lets staff message one another without a separate chat app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Leave Management$q$, $q$Employees submit time-off requests from the app, and managers approve or decline them with visibility into how the schedule and coverage will be affected.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Labor Cost & Wage Budgeting$q$, $q$Set target labor-cost percentages or wage budgets per location and see estimated costs update in real time as a schedule is built, helping control overtime spend.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Compliance Alerts$q$, $q$Automated checks flag potential rest-break violations, overtime thresholds, and award or union pay-rule conflicts before a schedule is published.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Payroll & HR Integrations$q$, $q$Connects to payroll and HR providers such as Gusto, QuickBooks, Xero, and ADP, plus Deputy's own US payroll offering delivered through a partnership with Paycor.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Intuitive drag-and-drop scheduling with mobile apps for both managers and shift staff$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Strong built-in compliance tooling for break, overtime, and award-rule violations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Broad integration ecosystem with popular payroll and point-of-sale systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Tiered pricing lets a business start with basic scheduling and add automation later$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Tablet kiosk clock-in with photo capture helps reduce buddy punching and time theft$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Auto-scheduling, demand forecasting, and other automation are locked behind the Core and Pro tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Add-ons such as Messaging+, Analytics+, and the HR module raise the effective per-user cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$A minimum monthly account spend can make Deputy relatively expensive for very small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$The web admin dashboard is English-only, unlike the mobile apps which support more languages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Full native payroll processing depends on regional partners rather than being built in natively everywhere$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$What is Deputy used for?$q$, $q$Deputy is used to build employee schedules, track time and attendance, assign shift-based tasks, and communicate with hourly or shift-based staff, primarily in retail, hospitality, and healthcare businesses.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Does Deputy offer a free plan?$q$, $q$Deputy does not have a permanent free plan; it offers a free trial on its paid plans, after which a subscription (starting with the Lite plan) is required, subject to a minimum monthly account spend.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$How much does Deputy cost?$q$, $q$Deputy's Lite plan starts at around $5 USD per user per month, with Core and Pro tiers priced higher for additional automation, custom access levels, and support features; optional add-ons are billed separately.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Does Deputy integrate with payroll software?$q$, $q$Yes. Deputy integrates with payroll and HR providers including Gusto, QuickBooks, Xero, and ADP, and also offers its own Deputy Payroll product in the US through a partnership with Paycor.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Is there a Deputy mobile app?$q$, $q$Yes. Deputy has mobile apps for iOS and Android that let employees view schedules, clock in and out, request shift swaps or leave, and receive shift notes and announcements.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Multi-location retail scheduling$q$, $q$Regional or national retail chains use Deputy to standardize how store managers build weekly rosters, track hours against budgets, and keep schedules consistent across locations.$q$, $q$Retail operations and store managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Restaurant and hospitality shift management$q$, $q$Cafes, restaurants, and hotels use Deputy's compliance alerts and shift-swap tools to manage frequently changing rosters while staying within break and overtime rules.$q$, $q$Restaurant and hospitality managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Healthcare and aged-care shift coverage$q$, $q$Care facilities use Deputy to fill recurring shifts, track staff qualifications and certifications, and log time worked for compliance and payroll purposes.$q$, $q$Healthcare and aged-care administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Replacing spreadsheet and paper scheduling$q$, $q$Small businesses moving off paper rosters or shared spreadsheets use Deputy's Lite plan to centralize scheduling and time tracking without a large upfront system change.$q$, $q$Small business owners and office managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Lite$q$, $q$$5 USD per user/month$q$, $q$Monthly or annual billing options$q$, $q$["Basic employee scheduling","Time clocking and timesheets","Labor law compliance alerts","Shift swaps and leave management","Basic reporting and messaging","Payroll and HR integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Core$q$, $q$$6.50 USD per user/month$q$, $q$Monthly or annual billing options$q$, $q$["Everything in Lite","Advanced scheduling tools","Timesheet auto-approval","Biometric clock-in options","Auto-scheduling and demand forecasting","Wage and labor budget tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Pro$q$, $q$$9 USD per user/month$q$, $q$Monthly or annual billing options$q$, $q$["Everything in Core","Custom access levels and location hierarchies","Advanced timesheets and pay centers","Single sign-on (SSO)","Sandbox test environment","24/7 live chat and dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Deputy is a workforce management platform built for businesses that schedule hourly, shift-based employees. Founded in 2008 and headquartered in Sydney, Australia, the company grew out of the everyday problem of coordinating rosters, timesheets, and staff communication for retail and hospitality teams, and has since expanded into healthcare, hospitality, and other shift-heavy industries worldwide.$q$, $q$At its core, Deputy combines four functions in one system: employee scheduling, time and attendance tracking, task management, and team communication. Managers build schedules from a web dashboard or the mobile app, staff clock in and out through the mobile app, a tablet kiosk, or a browser, and shift notes and announcements flow through the same tool employees already check for their upcoming shifts.$q$, $q$Deputy is not a full payroll processor or a broad HR information system on its own; it is scoped around the scheduling-and-timekeeping layer, then extends outward through integrations with payroll providers such as Gusto, QuickBooks, Xero, and ADP, plus its own Deputy Payroll option in the US delivered via a partnership with Paycor. That makes it best understood as a scheduling and timekeeping hub that plugs into whatever payroll stack a business already runs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$who-deputy-is-for$q$, $q$Who Deputy Is For$q$, 2, ARRAY[$q$Deputy is aimed at operations managers, store or restaurant owners, and HR teams responsible for building repeating shift rosters for hourly staff. Retail chains, cafes, restaurants, hotels, and healthcare or aged-care providers with fluctuating, demand-driven staffing needs are the clearest fit, especially once a business runs more than one location and needs a consistent way to build and publish schedules.$q$, $q$It also suits businesses that care about labor-law compliance, since Deputy can flag rest-break violations, overtime thresholds, and award or union pay-rule conflicts before a schedule is published. Multi-location employers who need visibility across sites, and who want staff to self-manage availability, shift swaps, and leave requests from their phones, tend to get the most value from the platform.$q$, $q$Growing companies that expect to add more automation over time are a good match too, because Deputy's tiered plans let a business start with basic scheduling and timesheets, then step up to auto-scheduling, demand forecasting, and labor-cost budgeting as headcount and complexity increase, without switching systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Companies with a fully salaried, non-shift workforce -- most software, agency, or professional-services teams, for example -- generally don't need Deputy's rostering and time-clock machinery and are better served by a lighter HR or project-tracking tool. If nobody in the business clocks in against a schedule, Deputy's core value proposition mostly disappears.$q$, $q$Very small, single-location teams that are highly cost-sensitive may also find it a poor fit: Deputy has no permanent free plan, and a minimum monthly account spend applies regardless of headcount, which can make the effective per-user cost high for a handful of part-time staff. Businesses whose admin staff need a fully localized back-office experience should also note that the web dashboard is English-only; only the mobile apps offer other languages.$q$, $q$Finally, organizations that want one vendor to run scheduling, time tracking, and full payroll natively end-to-end may be disappointed that Deputy's own payroll product is currently US-specific and delivered through a partner rather than built entirely in-house, meaning payroll in other regions still runs through a separate connected provider.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Scheduling is the anchor feature: managers build shifts with drag-and-drop tools, copy previous weeks, apply templates, and account for staff availability and qualifications, while employees see their upcoming shifts and can request swaps or additional coverage from the app. Time and attendance builds on the same schedule data, letting staff clock in and out via mobile, a shared tablet kiosk with photo capture, or a browser, with timesheets that reconcile automatically against the planned roster.$q$, $q$On top of scheduling and time tracking, Deputy layers task management (checklists tied to a shift, such as opening or closing duties), a news-feed style communication tool for shift notes and company announcements, and leave management for time-off requests and approvals. Higher plan tiers add auto-scheduling suggestions and demand forecasting that use historical sales or foot-traffic data to recommend staffing levels, along with wage and labor budget tracking to keep shift costs inside a target percentage.$q$, $q$Compliance and reporting round out the feature set: built-in alerts for rest breaks, overtime, and award or union rules help reduce costly scheduling mistakes, while reporting dashboards and an optional analytics add-on surface labor-cost and attendance trends. Deputy also connects to a broad set of payroll, point-of-sale, and HR systems, so scheduling and time data can flow into whatever back-office software a business already relies on.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$deputy-experience$q$, $q$The Deputy Experience$q$, 2, ARRAY[$q$For managers, the day-to-day experience centers on a schedule-building screen that feels closer to a calendar app than a spreadsheet: shifts can be dragged into place, copied from a prior week, and published to the whole team in a couple of clicks. Onboarding a new location generally means importing staff, setting availability and pay rules, and building the first roster, which most teams can do without vendor help.$q$, $q$For frontline employees, the mobile app is the main touchpoint -- checking upcoming shifts, requesting a swap or time off, clocking in when a shift starts, and reading shift notes or team announcements all happen in the same place, which cuts down on separate group chats or printed schedules pinned to a break-room wall.$q$, $q$Overall, Deputy reads as a purpose-built tool rather than a general-purpose suite: it does scheduling, time tracking, tasking, and shift communication well, and it is honest about routing full payroll processing through partners rather than owning that layer everywhere. Businesses evaluating it should weigh the tiered pricing and add-on costs against how much of the automation (auto-scheduling, demand forecasting, analytics) they actually need on day one versus later.$q$]::text[], 4);
