INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Text-based editing$q$, $q$Edit audio and video by cutting, moving, or retyping words in an automatically generated transcript, with the underlying media updating to match.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Overdub (AI voice cloning)$q$, $q$Create a synthetic version of your own consented voice to generate new narration or fix flubbed words without re-recording.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Studio Sound$q$, $q$AI-driven audio cleanup that reduces background noise and normalizes recording quality, useful for remote or inconsistent audio sources.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Filler word and silence removal$q$, $q$Automatically detects and removes filler words like "um" and "uh" as well as dead air, speeding up rough-cut editing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Eye Contact$q$, $q$AI adjustment that shifts a speaker's on-camera gaze to appear more directly at the lens, even if they were reading off to the side.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Screen recording$q$, $q$Built-in screen capture for creating tutorials, product demos, and walkthroughs directly inside the app.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Multitrack timeline$q$, $q$A conventional timeline view for layering video, audio, music, and effects alongside the transcript-based editor.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Templates and publishing$q$, $q$Pre-built templates for short-form social clips plus export and publishing options aimed at video and podcast platforms.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Collaboration and version history$q$, $q$Shared cloud workspaces with commenting and version history so teams can review and edit projects together.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Transcript-based editing significantly speeds up rough cuts for interviews, podcasts, and talking-head video$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Much lower learning curve than traditional timeline-based editors like Premiere Pro or Final Cut Pro$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Overdub and Studio Sound reduce the need for reshoots or professional-grade recording setups$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Cloud-based projects make team collaboration and review straightforward$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Built-in templates and publishing options simplify producing short-form social content$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Not designed for advanced color grading, VFX, or professional post-production finishing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Cloud-dependent processing can slow down with very long recordings or large video files$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Free plan is limited, and costs can add up for teams that need multiple seats with full AI features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Transcription and AI feature accuracy can vary depending on audio quality and speaker accents$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$AI voice cloning through Overdub raises consent and authenticity questions some users find uncomfortable$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$What is Descript used for?$q$, $q$Descript is used to edit audio and video by editing a text transcript of the recording, and is commonly used for podcasts, YouTube videos, webinars, tutorials, and marketing video content.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Does Descript work with both audio and video?$q$, $q$Yes. Descript supports both audio-only projects, like podcasts, and video projects, including screen recordings and talking-head footage, within the same transcript-based editing workflow.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Is Descript free to use?$q$, $q$Descript offers a free plan with limited monthly usage, alongside paid plans that unlock more transcription time and features like Overdub, Studio Sound, and watermark-free exports.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$What is Overdub in Descript?$q$, $q$Overdub is Descript's AI voice-cloning feature. After training on a consented voice sample, it can generate new narration or correct mispronounced words in your own voice without requiring a re-recording session.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Is Descript available on both Mac and Windows?$q$, $q$Yes, Descript is available as a desktop application for both macOS and Windows, with projects synced through the cloud.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Podcast production and editing$q$, $q$Podcasters use Descript to transcribe recordings, cut interviews down by editing text, remove filler words and dead air, and clean up remote guest audio with Studio Sound before publishing.$q$, $q$Podcasters and audio producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$YouTube and talking-head video creation$q$, $q$Video creators use Descript's transcript editing, filler-word removal, and Eye Contact tool to produce polished talking-head videos faster than with a traditional timeline editor.$q$, $q$YouTubers and video content creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Marketing videos, webinars, and demos$q$, $q$Marketing and communications teams use built-in screen recording and templated social exports to produce product demos, webinars, and short promotional clips without needing dedicated video editors.$q$, $q$Marketing and communications teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Course and tutorial creation$q$, $q$Educators and course creators record screen-capture tutorials, then use transcript editing to tighten explanations and remove mistakes before publishing lessons.$q$, $q$Educators and online course creators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Limited monthly transcription time","Text-based editing","Basic screen recording","Watermarked exports on some features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Creator$q$, $q$Paid, billed monthly or annually$q$, $q$Monthly or annual$q$, $q$["More transcription time than the free plan","Overdub voice generation","Studio Sound noise removal","No watermark on exports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Business$q$, $q$Paid, billed monthly or annually$q$, $q$Monthly or annual$q$, $q$["Expanded transcription time and team seats","Priority processing for AI features","Advanced collaboration and admin controls","Brand kit and additional publishing options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, $q$["Custom seat and usage limits","Dedicated support","Advanced security and admin controls","Custom contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Descript is an audio and video editing application built around a deceptively simple idea: if a computer can transcribe what's being said, you should be able to edit the recording by editing the text. Instead of scrubbing a timeline frame by frame, users cut, rearrange, or delete words in a transcript, and the underlying audio or video updates to match. That core mechanic turns editing into something closer to word processing, which is a meaningful shift for anyone who records a lot of spoken-word content but doesn't have formal training in traditional non-linear editing software.$q$, $q$The company was founded in 2017 by Andrew Mason (previously known as the co-founder and CEO of Groupon) and is based in San Francisco. Descript started as a transcription and podcast-editing tool and has since expanded into a broader production suite that includes screen recording, multitrack video editing, AI voice generation through a feature called Overdub, and automated audio cleanup via Studio Sound. More recently the product has layered in a set of AI-assisted editing tools, sometimes referred to under the internal branding "Underlord," aimed at automating repetitive editing tasks like removing filler words or silences.$q$, $q$Descript positions itself less as a replacement for high-end professional editing suites and more as an accessible, faster path to a finished podcast episode, talking-head video, tutorial, or marketing clip. It runs as a desktop app (Mac and Windows) with cloud-synced projects, so editing, transcription, and AI processing happen with an internet connection even though the interface itself is a native application.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$who-descript-is-for$q$, $q$Who Descript Is For$q$, 2, ARRAY[$q$Descript is best suited to people who produce a steady volume of spoken-word content and want to spend less time on the mechanical parts of editing. Podcasters are the clearest fit: transcript-based editing makes it fast to cut dead air, remove tangents, and tighten interviews, while Studio Sound and Overdub help clean up inconsistent recording conditions across remote guests.$q$, $q$YouTubers, course creators, and educators who film themselves talking to a camera also benefit, particularly from features like automatic filler-word removal and the Eye Contact tool, which nudges on-camera gaze toward the lens even when the speaker was reading a script off to the side. For these creators, Descript can meaningfully shorten the gap between a raw recording and a publishable video.$q$, $q$Marketing and communications teams that produce webinars, product demos, internal training videos, or short social clips are another strong match, since Descript's screen recording, templated exports for social formats, and shared cloud workspace make it easier for non-editors on a team to contribute to video production without learning a full NLE.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Professional film and broadcast editors who need frame-accurate trimming, advanced color grading, layered VFX compositing, or deep audio mixing with plugin chains will likely find Descript's toolset comparatively shallow next to dedicated tools like Premiere Pro, DaVinci Resolve, or Pro Tools. Descript can get a project most of the way there, but it isn't built to be the final stop for high-end post-production.$q$, $q$Because Descript's AI features and project sync depend on cloud processing, users working with very long recordings, large 4K video files, or unreliable internet connections may run into slower transcription and rendering times than they would in a fully local, offline editing workflow.$q$, $q$Anyone expecting unlimited functionality on the free tier, or teams with tight budgets needing many seats with full AI features, should look closely at plan limits before committing, since features like Overdub, Studio Sound, and extended transcription time are generally gated behind paid plans.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of Descript is transcript-based editing: recordings are automatically transcribed, and deleting, moving, or retyping words in that transcript edits the underlying audio or video in place. This is paired with a more conventional multitrack timeline for users who want finer manual control over layering clips, music, and sound effects alongside the text view.$q$, $q$Overdub is Descript's AI voice-cloning feature, letting a user train a synthetic version of their own voice (with consent) to generate new narration or patch over a mispronounced word without a re-recording session. Studio Sound applies AI-based noise reduction and audio enhancement to make recordings sound closer to studio quality, which is particularly useful for remote interviews recorded on inconsistent microphones. Filler word removal and silence removal automate two of the most tedious parts of rough-cut editing, and the Eye Contact feature adjusts a speaker's gaze in video to appear more directly at the camera.$q$, $q$Beyond the core editor, Descript includes built-in screen recording for tutorials and demos, publishing and export options aimed at podcast platforms and social video formats, ready-made templates for short-form social clips, and collaboration tools such as shared workspaces, comments, and version history so teams can review and edit projects together in the cloud.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$descript-experience$q$, $q$The Descript Experience$q$, 2, ARRAY[$q$Using Descript feels closer to working in a word processor than in a traditional video editor, which is by design. New users typically import or record a file, wait for automatic transcription, and then start editing directly in the text panel, with the timeline view available for anything that requires more visual precision. The learning curve is noticeably shallower than tools like Premiere Pro or Final Cut Pro, especially for anyone already comfortable editing documents.$q$, $q$Because projects live in the cloud, switching between the desktop app and collaborating with teammates is generally smooth, and changes sync automatically. That said, very large video files or long-form recordings can slow down transcription and AI processing, and users have reported that performance depends noticeably on file size, internet connection, and how much AI-driven processing (like Studio Sound or Overdub) is applied.$q$, $q$Descript maintains documentation, tutorials, and an active user community to help people get comfortable with its more advanced AI features, and the product continues to add new AI-assisted editing capabilities over time, which means the interface and feature set can shift meaningfully between visits for less frequent users.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
