INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Autonomous task planning and execution$q$, $q$Devin breaks a plain-language task into steps and carries them out itself, rather than only suggesting code for a human to run.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Sandboxed dev environment$q$, $q$Each session runs in its own shell, code editor, and browser, so Devin can install dependencies, run scripts, and browse documentation while it works.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$GitHub integration and pull requests$q$, $q$Devin clones and works directly in a connected repository, then opens a pull request with a summary of the change for human review.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Devin Review$q$, $q$An automated pull request review tool that comments on incoming code changes, available for free on public repositories.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$DeepWiki documentation generation$q$, $q$Automatically generates and maintains searchable documentation for a codebase, so teams don't have to write it by hand.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Slack, Linear, and Jira integrations$q$, $q$Tasks can be assigned to Devin directly from a chat message or an existing ticket instead of a separate interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Model Context Protocol support$q$, $q$Connects Devin to additional internal or third-party tools beyond its built-in integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Session replay and logging$q$, $q$Every command, file edit, and test run in a session is recorded, giving reviewers a full trace of how a result was reached.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise SSO and admin controls$q$, $q$SAML and OIDC single sign-on, centralized admin management, and an optional dedicated deployment for larger organizations.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Carries a task through to a finished, tested pull request instead of only suggesting code snippets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Session logs and replays make it possible to see exactly what commands and edits produced a given result$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Integrates directly into existing GitHub, Slack, and Linear workflows without changing how work is assigned$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Free companion tools like Devin Review and DeepWiki provide value even outside a paid plan$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise options such as SSO and dedicated deployment support larger, security-conscious engineering organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Usage-based credit billing can make costs harder to predict than a flat per-seat subscription$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Best results depend on a codebase having reasonable test coverage for Devin to verify its own work against$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Not designed for fast, line-by-line pairing the way inline IDE coding assistants are$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Ambiguous, judgment-heavy tasks still require close human review rather than full delegation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise pricing is custom and requires contacting sales rather than a published rate$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Is Devin free to use?$q$, $q$Devin has a free plan with limited weekly usage, plus paid Pro and Max plans and a Teams plan for organizations, each adding higher usage quotas and additional features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$What is an ACU in Devin's pricing?$q$, $q$An ACU, or Agent Compute Unit, is Cognition's normalized measure of the compute, model inference, and time Devin actively spends working on a task; enterprise plans are billed against ACU usage, while self-serve plans combine a flat monthly quota with pay-as-you-go credits.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Does Devin work with any programming language?$q$, $q$Devin is built to operate like a general software engineer inside its sandboxed environment, so it can work across most common languages and frameworks, though how well it performs on a given codebase still depends on that project's existing tests and conventions.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Does Devin replace human developers?$q$, $q$Cognition positions Devin as a collaborator that takes on bounded, well-defined engineering tasks under human oversight, not a full replacement; pull requests still go through human review before merging.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$How is Devin different from Windsurf?$q$, $q$Devin is Cognition's autonomous coding agent that completes assigned tasks on its own, while Windsurf, which Cognition acquired in 2025, is a separate AI-native code editor built for interactive, in-editor coding assistance.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Legacy code migrations and upgrades$q$, $q$Devin can work through large, repetitive migration tasks such as framework version bumps or language ports, verifying each change against the existing test suite before opening a pull request.$q$, $q$Platform and infrastructure engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Automated pull request review$q$, $q$Devin Review comments on incoming pull requests to catch issues before a human reviewer looks at the change, adding an extra check to the existing review process.$q$, $q$Engineering teams practicing code review at scale$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Bug triage and ticket resolution$q$, $q$Individual bug tickets can be assigned to Devin directly from Linear or Jira, letting it investigate, fix, and open a pull request without a human first digging into the codebase.$q$, $q$Product engineering teams with active issue backlogs$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Codebase documentation$q$, $q$DeepWiki generates and keeps searchable documentation up to date for a repository, giving new engineers a reference without someone writing it by hand.$q$, $q$Teams onboarding engineers or maintaining large repositories$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["Limited Devin usage each week","Access to Devin Review on public pull requests","Access to DeepWiki documentation lookup","Single-user account"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Pro$q$, $q$$20$q$, $q$Monthly$q$, $q$["Daily and weekly usage quota for sessions, CLI, and desktop","Pay-as-you-go credits beyond the included quota","Slack, Linear, and MCP integrations","Single-user account"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Teams$q$, $q$$80 + $40 per full seat$q$, $q$Monthly$q$, $q$["Unlimited team members with shared, pooled credits","Full seats include Pro-level quota plus desktop access","Free flex seats that draw from shared team credits","Centralized billing and admin analytics dashboard"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, $q$["Volume ACU-based billing via a custom order form","SAML and OIDC single sign-on","Dedicated account management and priority support","Optional dedicated deployment environment"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Devin is an autonomous AI software engineer built by Cognition, a company founded in 2023. Rather than acting as a code-completion sidekick that suggests the next line as a developer types, Devin is designed to take a task described in plain language and carry it through to a finished, testable result on its own. It works inside a sandboxed environment that includes its own shell, code editor, and browser, which lets it read a codebase, plan a sequence of steps, and then actually execute those steps instead of only describing them.$q$, $q$In practice, Devin clones the relevant repository, forms a plan for the assigned task, writes code, runs the project's existing test suite, and iterates when something fails, much the way a human engineer would debug their own change before asking for review. When the work is ready, Devin opens a pull request with a summary of what it did and why, so a human reviewer can approve, request changes, or take over. Every action it takes inside its sandbox is logged and replayable, which gives engineers visibility into how a result was reached rather than just the end diff.$q$, $q$Devin is built to plug into workflows teams already use: it connects to GitHub for code and pull requests, and to tools like Slack, Linear, and Jira so tasks can be assigned from a ticket or a chat message. Cognition also ships companion tools alongside the core agent, including Devin Review for automated pull request feedback and DeepWiki for auto-generated codebase documentation. In 2025, Cognition also acquired Windsurf, the AI-native code editor, though Windsurf remains a separate interactive coding product distinct from Devin's autonomous, task-based agent.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$who-devin-is-for$q$, $q$Who Devin Is For$q$, 2, ARRAY[$q$Devin fits engineering teams that have a backlog of well-scoped, repetitive work: dependency and framework upgrades, large-scale refactors, flaky test fixes, and migrating code between languages or platforms. These tasks tend to have a clear definition of done, which is exactly the kind of assignment an autonomous agent can verify against a test suite and hand back as a reviewable pull request rather than an open-ended conversation.$q$, $q$It's also a strong fit for organizations already standardized on GitHub, Slack, Linear, or Jira, since Devin can be assigned work directly from an existing ticket or channel without changing how the team plans its work. Teams maintaining large or older codebases that need steady modernization, rather than a single rewrite, get particular value from an agent that can work through many similar tickets in parallel across a monorepo or multiple repositories.$q$, $q$Individual senior engineers and tech leads can also use Devin as an extra set of hands for the engineering toil that would otherwise interrupt deeper work: cleaning up boilerplate, writing one-off migration scripts, or triaging a stack of minor bug reports. In that setup, Devin absorbs the lower-judgment tasks while the human stays focused on architecture and code review.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Devin relies heavily on being able to verify its own work, so codebases with little or no automated testing and CI give it much less to check its output against, and results in that setting are harder to trust without close review. Teams working in early-stage, rapidly changing prototypes with no established conventions may find that the agent has less structure to plan against than it does in a mature, well-tested repository.$q$, $q$Developers who mainly want fast, line-by-line pairing while they type, rather than delegating a whole task, are likely better served by an inline coding assistant or IDE-based tool. Devin's model is built around independent, multi-step sessions rather than continuous keystroke-level suggestions, so it solves a different problem than a typical autocomplete-style assistant.$q$, $q$Budget-conscious individuals and hobbyists making many small, exploratory changes may also find that Devin's metered, credit-based usage adds up faster than a flat-rate subscription tool would for the same volume of small edits. Because billing is tied to active agent work rather than a fixed per-seat rate alone, costs are less predictable for workloads that consist of many short, ad hoc sessions.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Devin is its planning and execution loop: given a task description, it breaks the work into steps, then carries them out inside its own sandboxed shell, editor, and browser rather than only producing suggested code. This lets it install dependencies, run scripts, browse documentation, and re-run tests as part of completing a task, closing the loop between writing code and confirming it works.$q$, $q$Around that core agent, Devin integrates with the tools engineering teams already run day to day: GitHub for repositories and pull requests, Slack and Linear for assigning and tracking tasks, and the Model Context Protocol for connecting additional internal or third-party tools. Companion products extend this further, with Devin Review offering automated pull request feedback and DeepWiki generating and maintaining codebase documentation that engineers can search.$q$, $q$For larger organizations, Devin's enterprise tier adds administrative and security controls on top of the core agent, including SAML and OIDC single sign-on, centralized admin management, and the option of a dedicated deployment. Session recordings and step-by-step logs are available across plans, giving reviewers a full account of the commands, edits, and test runs behind any given pull request.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$the-devin-experience$q$, $q$The Devin Experience$q$, 2, ARRAY[$q$Getting started with Devin means connecting a GitHub repository through Cognition's app, after which Devin indexes the codebase so it has context on the project's structure and conventions. From there, a task is assigned much like it would be to a teammate: a short description in a chat window, a Slack message, or an existing ticket, rather than a detailed technical specification.$q$, $q$Once a session starts, engineers can watch Devin work in something close to real time, seeing the shell commands it runs, the files it edits, and the pages it visits in its sandboxed browser. Users can step in to redirect the approach, answer a clarifying question, or simply let the session run unattended and check back once it opens a pull request with a summary of the change.$q$, $q$How well that experience lands tends to depend on the codebase it's pointed at: engineers report the strongest results on repetitive, clearly scoped tickets in projects with decent test coverage, where Devin's own test runs give confidence in the result. Tasks that hinge on ambiguous product decisions or unwritten architectural context still need a human to weigh in, which is consistent with Cognition positioning Devin as a collaborator that takes on bounded engineering work rather than a fully independent replacement for a developer.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Multi-channel document capture$q$, $q$Submit receipts and invoices via the mobile app camera, a dedicated forwarding email address, direct file upload, or browser extension, so paperwork can be captured wherever it originates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$AI-powered data extraction$q$, $q$OCR combined with AI reads supplier names, dates, totals, tax amounts, and line items off receipts and invoices, reducing the need to manually key in transaction details.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Accounting software integrations$q$, $q$Extracted data syncs directly into Xero, QuickBooks, Sage, and a range of other accounting platforms, keeping the general ledger up to date without a separate import step.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Bank statement fetching$q$, $q$Securely connect business bank accounts to pull in statement data automatically, complementing receipt and invoice capture with transaction-level bank information.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Dext Precision$q$, $q$A compliance and data-quality layer, originally built on the Xavier Analytics acquisition, that scans client ledgers for duplicates, missing documents, and coding inconsistencies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Document storage and archiving$q$, $q$Digitized receipts and invoices are stored long-term in the platform, giving businesses and their accountants an audit-ready record without keeping paper files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Expense reports and approvals$q$, $q$Employees can submit expense claims with attached receipts through the app, and managers can review and approve them as part of a reimbursement workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Supplier statement reconciliation$q$, $q$Match supplier statements against invoices already recorded in the system to catch discrepancies before they turn into payment errors.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Multi-client practice dashboard$q$, $q$Accounting and bookkeeping firms can monitor document flow, outstanding items, and data quality across their entire client base from a single practice-level view.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Cuts a substantial amount of manual data entry for receipts, invoices, and bank statements$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Deep, direct integrations with major accounting platforms including Xero, QuickBooks, and Sage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Long-established product in the accounting-tech space, built on the original Receipt Bank foundation since 2010$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Practice-level tools like Dext Precision help firms manage data quality across many clients at once$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Mobile app makes it easy for business owners and employees to submit receipts as expenses happen$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$No permanent free plan, and cost scales with both user count and document volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Value depends heavily on using a supported accounting platform, limiting its appeal outside that ecosystem$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Bank statement and line-item extraction can be metered through a credit system on lower-tier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Extraction accuracy can dip on non-standard, handwritten, or non-English documents, requiring manual fixes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Published, self-serve pricing is limited, especially for accounting-practice plans, making upfront cost comparison harder$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$What does Dext actually do?$q$, $q$Dext captures receipts, invoices, and bank statements through its mobile app, email forwarding, or bank connections, uses OCR and AI to extract the key data from each document, and syncs that data into accounting software like Xero, QuickBooks, or Sage.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Is Dext the same company as Receipt Bank?$q$, $q$Yes. Dext is the rebranded name of Receipt Bank, a bookkeeping automation company founded in London in 2010. It adopted the Dext name in 2020 as it expanded beyond receipt capture into data-quality and analytics tools.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$What accounting software does Dext integrate with?$q$, $q$Dext integrates with a range of accounting platforms, most notably Xero, QuickBooks, and Sage, allowing extracted receipt, invoice, and bank data to sync directly into a business's existing ledger.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Does Dext have a free plan?$q$, $q$Dext does not offer a permanent free tier. It provides a 14-day free trial without requiring a credit card, after which users choose a paid plan based on user count and document volume.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Who owns Dext now?$q$, $q$Dext was acquired by private equity firm Hg in 2021 and, following that, became part of IRIS Software Group after an acquisition in late 2024.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Multi-client bookkeeping practices$q$, $q$Accounting and bookkeeping firms use Dext to standardize how every client submits receipts and invoices, then monitor document flow and data quality across the whole client base from one dashboard.$q$, $q$Accounting and bookkeeping firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Small business expense digitization$q$, $q$Business owners use the mobile app to photograph receipts as they're generated, eliminating the end-of-month scramble to find paper records before syncing clean data to their accounting platform.$q$, $q$Small and mid-sized business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Employee expense claims$q$, $q$Teams with staff who incur work expenses use Dext to submit and approve expense reports with attached receipts, feeding approved reimbursements straight into the accounting system.$q$, $q$Finance and operations teams managing employee expenses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Ledger data-quality checks$q$, $q$Bookkeepers use Dext Precision to scan client ledgers for duplicate entries, missing documents, and coding errors before month-end close or a tax filing deadline.$q$, $q$Bookkeepers and accountants responsible for ledger accuracy$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Free Trial$q$, $q$Free$q$, $q$14-day trial, no credit card required$q$, $q$["Full access to core Business plan features","Mobile app receipt and invoice capture","AI data extraction","Accounting software sync"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Business$q$, $q$From $31.50/month ($25.21/month billed annually)$q$, $q$Monthly or annual$q$, $q$["5 users and 250 documents per month included, scaling with added users","Receipt, invoice, and bank statement capture","Sync to Xero, QuickBooks, Sage, and other platforms","Included credits for bank statement and line-item extraction","Optional Commerce add-on for e-commerce sales data"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Practice Essentials$q$, $q$From around $239.19/month for accounting firms (scales with client count)$q$, $q$Monthly$q$, $q$["Mobile document capture and bank statement extraction across clients","Core automation and coding rules","Per-client pricing that decreases as more clients are added","Credit system for additional extraction types"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Practice Advanced$q$, $q$Custom / contact sales$q$, $q$Monthly$q$, $q$["Everything in Practice Essentials","Team and location setup with custom workflows","Dext Precision data-quality and compliance insights","Advanced automation across the full client roster"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dext is a cloud-based bookkeeping automation platform that removes manual data entry from the process of recording receipts, invoices, and bank transactions. It was founded in 2010 in London as Receipt Bank, and after a decade of building tools for accountants and bookkeepers, the company rebranded to Dext in 2020 to reflect a broader product line that goes beyond simple receipt scanning. Dext was acquired by private equity firm Hg in 2021 and, more recently, by IRIS Software Group in late 2024, placing it inside a larger portfolio of accounting and compliance software.$q$, $q$The core workflow is straightforward: a user submits a document by snapping a photo in the mobile app, forwarding an email, uploading a PDF, or connecting a bank feed. Dext's OCR and AI engine then reads the document, pulls out the supplier, date, line items, and tax detail, and lets the user (or their bookkeeper) review and approve the extracted data before it is pushed into an accounting platform such as Xero, QuickBooks, or Sage. The goal is to turn a shoebox of paper receipts, or an inbox full of PDF invoices, into structured, categorized transactions with minimal typing.$q$, $q$Dext is really a family of products rather than a single tool. Dext Prepare handles capture and extraction, Dext Precision (built on the Xavier Analytics acquisition) runs data-quality and compliance checks across a bookkeeper's client base, and Dext Commerce pulls in sales data from e-commerce and payment platforms. The product is sold both directly to businesses and, heavily, through accounting and bookkeeping firms who resell or bundle it as part of their client services, which shapes a lot of its feature set and pricing structure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$who-dext-is-for$q$, $q$Who Dext Is For$q$, 2, ARRAY[$q$Dext is built first and foremost for accounting and bookkeeping practices that process paperwork for many clients at once. Firms that want a single dashboard to monitor document flow, chase clients for missing receipts, and keep a consistent data pipeline into Xero, QuickBooks, or Sage across their whole client roster are the platform's core audience, and most of its practice-tier features (multi-client views, workflow controls, Precision's anomaly checks) are designed with that use case in mind.$q$, $q$Small and mid-sized businesses that already use one of Dext's supported accounting platforms are a strong secondary fit, particularly ones with a steady volume of receipts, supplier invoices, or expense claims from a team of employees. Retailers, hospitality operators, trades businesses, and professional services firms that want to stop chasing paper receipts and manually keying invoice line items can use Dext directly, without going through a bookkeeper.$q$, $q$Finance teams and bookkeepers who care about the accuracy of the numbers going into the ledger, not just the speed of getting them there, are also well served, since Dext Precision is specifically aimed at flagging duplicate entries, missing information, and other data-quality issues before they cause problems at tax time or during an audit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very low-volume users, such as sole traders or freelancers who handle only a handful of receipts a month, often find Dext's recurring subscription cost hard to justify next to simpler or cheaper receipt-capture tools, since Dext is priced and packaged around a minimum tier of users and document volume rather than true pay-as-you-go usage.$q$, $q$Businesses that don't use one of Dext's supported accounting platforms will lose much of the platform's value, because the payoff of automated capture depends on a clean sync into the general ledger; without that integration, Dext becomes a more expensive document scanner. Similarly, companies looking for an all-in-one accounting or invoicing suite should look elsewhere, as Dext is a data-capture and document-management layer that sits alongside accounting software, not a replacement for it.$q$, $q$Organizations that primarily deal in non-English or heavily handwritten documents, or that need extensive custom workflow logic beyond what Dext's rules and approval settings support, may also run into more manual correction and less flexibility than they expect, since the product's extraction accuracy and configurability are strongest around standard typed invoices and receipts in its core supported markets.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Dext captures documents through several channels: a mobile app for photographing receipts on the go, a dedicated forwarding email address for digital invoices, a browser-based upload, and direct bank feed connections for statement data. Once a document comes in, Dext's OCR and AI extraction reads the supplier name, date, amounts, tax, and line items, and applies supplier- or category-based rules so recurring expenses get coded consistently without the user re-entering the same details each time.$q$, $q$On the integration side, Dext connects to a large roster of accounting platforms, including Xero, QuickBooks, and Sage, and supports connections to thousands of banks for statement fetching, so extracted data flows directly into the correct ledger accounts rather than sitting in a separate silo. Document storage (sometimes referred to as Dext's Vault) keeps a long-term digital archive of every receipt and invoice, which is useful for audit trails and tax record-keeping requirements.$q$, $q$For accounting and bookkeeping firms, Dext Precision adds a compliance layer on top of the raw data, scanning client ledgers for anomalies such as duplicate transactions, missing invoices, or inconsistent coding, and surfacing them in a practice-wide dashboard. Additional capabilities include expense report submission and approval workflows for employee reimbursements, supplier statement reconciliation to match statements against recorded invoices, and Dext Commerce for pulling in e-commerce and payment platform sales data alongside standard expense documents.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$the-dext-experience$q$, $q$The Dext Experience$q$, 2, ARRAY[$q$Day to day, using Dext typically means snapping a photo of a receipt or forwarding an invoice email and then, periodically, reviewing a queue of extracted documents to confirm the supplier, category, and amounts before they're pushed to the connected accounting platform. For businesses with straightforward, standard-format documents, this review step is usually quick; more unusual formats, handwriting, or non-English text tend to require more manual correction.$q$, $q$Because Dext is so often deployed and configured by an accounting or bookkeeping firm on a client's behalf, the setup experience can feel different depending on who's driving it. A practice managing the connection, workflow rules, and chart-of-accounts mapping tends to have a smoother rollout than a business owner setting everything up alone for the first time, where getting integration mappings and approval rules right can take some trial and error.$q$, $q$Support is delivered through Dext's help centre, in-app guidance, and, for many customers, their accounting or bookkeeping partner rather than direct vendor contact. The mobile apps are generally straightforward for the core job of photographing and submitting a receipt, while the web dashboard is where most of the review, correction, and (for practices) multi-client oversight happens.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
