INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Real-time AI call transcription$q$, $q$Dialpad Ai transcribes phone calls, video meetings, and voicemails live as they happen, with the text appearing on screen alongside the conversation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Automatic call summaries and action items$q$, $q$After each call or meeting ends, Dialpad Ai generates a written summary and a list of follow-up items directly in the call log, cutting down on manual note-taking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Live sentiment analysis$q$, $q$Calls are analyzed in real time for sentiment shifts, helping managers and agents notice when a conversation is becoming tense or at risk without needing to listen back to a recording.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Real-time agent coaching cards$q$, $q$During live calls, Dialpad can surface contextual prompts, such as compliance reminders or suggested talking points, to help agents and reps handle the conversation in the moment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Cloud business phone system$q$, $q$Includes auto-attendants, ring groups, call routing, and extensions managed from a web-based admin console, with no desk-phone hardware required.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Number porting and provisioning$q$, $q$Existing local and toll-free numbers can typically be ported into Dialpad, and admins can provision new numbers and extensions for employees directly online.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Ai Contact Center tools$q$, $q$Adds queue management, supervisor monitoring and coaching, and post-call analytics for support and sales teams handling higher call volumes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Ai Meetings video conferencing$q$, $q$Video meetings share the same live transcription, summaries, and recording capabilities as phone calls, keeping the experience consistent across channels.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$CRM and productivity integrations$q$, $q$Native integrations with Salesforce, HubSpot, Google Workspace, and Microsoft 365 sync call activity and logs with tools teams already use.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Analytics and reporting dashboards$q$, $q$Admins and managers can track call volume, quality metrics, and agent or team performance trends from a centralized reporting view.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Built-in real-time AI transcription, summaries, and sentiment tracking without a separate add-on product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$No desk-phone hardware required; works from browser, desktop, and mobile apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Live coaching cues during calls are useful for onboarding new reps and agents$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$One platform covers phone, meetings, messaging, and contact center with shared analytics$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Self-service number porting and admin setup that doesn't require a technician visit$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Plan minimums, such as three users on the Pro plan, make it less economical for very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$The most advanced coaching and contact-center features are reserved for higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$The admin console and reporting depth can take new admins some time to learn$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Some users report inconsistent call quality on lower-bandwidth internet connections$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Enterprise pricing is quote-only, making upfront cost comparison harder$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Does Dialpad offer a free trial?$q$, $q$Yes, Dialpad offers free trial periods on its paid plans so teams can test calling, messaging, and AI features before committing to a subscription. Trial length and terms are set by Dialpad and may vary by plan or region.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Can I keep my existing business phone number?$q$, $q$Yes, Dialpad supports number porting, so existing local and toll-free numbers can typically be transferred from a previous carrier into the platform during setup.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$What does Dialpad Ai actually do during a call?$q$, $q$Dialpad Ai transcribes the conversation in real time, tracks sentiment, can surface coaching prompts to the agent while the call is happening, and produces a summary with action items once the call ends.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Does Dialpad integrate with CRM tools like Salesforce?$q$, $q$Yes, Dialpad offers native integrations with CRMs such as Salesforce and HubSpot, along with Google Workspace and Microsoft 365, though some integrations are gated to Pro-tier plans and above.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$What's the difference between Dialpad's Standard, Pro, and Enterprise plans?$q$, $q$Standard covers core calling and AI transcription with no minimum seat requirement, Pro adds CRM integrations and international messaging with a three-user minimum, and Enterprise adds SSO, unlimited ring groups, and an uptime SLA at a custom quoted price with a much higher user minimum.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Coaching remote and distributed sales teams$q$, $q$Sales managers use live sentiment tracking and call summaries to review rep performance and give feedback without needing to sit in on or replay every call.$q$, $q$Sales teams and sales managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Running a customer support contact center$q$, $q$Support teams use Ai Contact Center queue management, supervisor coaching, and post-call analytics to handle higher call volumes while monitoring quality in real time.$q$, $q$Customer support and CX teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Replacing a legacy desk-phone system$q$, $q$Small and mid-sized businesses migrate from on-premise PBX hardware to Dialpad's cloud phone system to reduce hardware costs and let employees take calls from any device.$q$, $q$Small and mid-sized businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Consolidating phone, meetings, and messaging$q$, $q$Multi-location or enterprise organizations replace several separate communication vendors with a single Dialpad subscription covering voice, video, and messaging under one admin console.$q$, $q$Enterprises and multi-location businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Standard$q$, $q$$15/user/month (annual), $27/user/month (monthly)$q$, $q$Monthly or annual$q$, $q$["No minimum user requirement","Unlimited calling within your country, plus the US and Canada","Local SMS and MMS messaging","AI-powered call and voicemail transcription","Standard integrations with Google Workspace and Microsoft 365"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Pro$q$, $q$$25/user/month (annual), $35/user/month (monthly)$q$, $q$Monthly or annual$q$, $q$["Three-user minimum","Everything in Standard","CRM integrations, including Salesforce and HubSpot","International SMS messaging","More advanced call routing and reporting options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual (custom contract)$q$, $q$["100-user minimum","Everything in Pro","Single sign-on (SSO)","Unlimited ring groups and office locations","Priority support and a 99.9% uptime SLA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dialpad is a cloud-based business communications platform founded in 2011 and headquartered in San Francisco. It combines a hosted business phone system with video meetings, team messaging, and an AI contact center in one browser-based and mobile app, replacing traditional on-premise PBX hardware with a subscription service.$q$, $q$What distinguishes Dialpad from most VoIP competitors is Dialpad Ai, a real-time voice intelligence layer built into every call. It transcribes conversations live, flags sentiment shifts, surfaces coaching prompts to reps during a call, and generates post-call summaries and action items automatically, without needing a separate transcription add-on.$q$, $q$The platform is sold as several connected products: Dialpad Ai Voice for business phone service, Dialpad Ai Contact Center for support and sales teams, and Dialpad Ai Meetings for video conferencing, all sharing the same admin console, analytics layer, and AI engine so data and insights carry across channels.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$who-dialpad-is-for$q$, $q$Who Dialpad Is For$q$, 2, ARRAY[$q$Dialpad fits small and mid-sized businesses that want to retire a legacy desk-phone system, or a patchwork of separate calling, meeting, and messaging tools, in favor of one cloud subscription that works from a laptop, browser, or phone app.$q$, $q$Sales and support teams get particular value from the built-in AI: call summaries save reps from manual note-taking, sentiment tracking helps managers spot at-risk conversations, and coaching cues can nudge new hires toward better talk tracks during a live call rather than only in a review afterward.$q$, $q$Distributed and remote-first companies also suit Dialpad well, since every extension, voicemail, and call recording lives in the cloud and is reachable from any device, and admins can provision or reassign numbers between employees without shipping hardware or scheduling a technician visit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small teams or solo operators who only need a couple of numbers may find Dialpad's per-user pricing and plan minimums, three users on the Pro plan and considerably more on Enterprise, less economical than a lighter-weight virtual number app built for one or two users.$q$, $q$Organizations with heavy on-premise telephony investments, complex legacy PBX integrations, or strict data-residency requirements outside Dialpad's supported regions may find migration more disruptive than the AI features are worth, at least until those constraints are resolved.$q$, $q$Teams that mainly need a simple, no-frills calling app without transcription, coaching, or analytics might find Dialpad's interface and admin console more feature-dense than necessary, and could get comparable core calling functionality for less from a stripped-down competitor.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of the platform is Dialpad Ai, which transcribes calls and meetings in real time, generates automatic summaries and action items, tracks call sentiment, and can surface live coaching cards, such as compliance reminders or objection-handling tips, while a conversation is still happening.$q$, $q$On the phone system side, Dialpad provides standard business calling features, auto-attendants, call routing and ring groups, local and toll-free numbers, number porting, voicemail transcription, and calling within supported countries, delivered through desktop, web, and mobile apps rather than desk hardware.$q$, $q$The Ai Contact Center adds queue management, supervisor coaching tools, and post-call analytics for support teams, while Ai Meetings covers video conferencing with the same live transcription and summaries, and native integrations with Google Workspace, Microsoft 365, Salesforce, and HubSpot help the platform fit into existing workflows.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$the-dialpad-experience$q$, $q$The Dialpad Experience$q$, 2, ARRAY[$q$Setup is largely self-service: admins can port existing numbers, assign extensions, and configure call routing from a web-based console without needing a dedicated telecom technician, and most users are placing and receiving calls from the desktop or mobile app the same day.$q$, $q$Day-to-day, the AI layer is the most noticeable part of the experience: live transcripts scroll alongside a call, a summary and follow-up items appear in the call log within moments of hanging up, and managers can review sentiment trends across a team without listening to every recording.$q$, $q$Reporting and admin tools are comprehensive enough for larger teams to track call volume, quality, and agent performance, though that same depth means new admins typically need some time to learn the console, and the richer AI coaching and contact-center capabilities are concentrated in the higher-priced plans.$q$]::text[], 4);
